INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027941e3c98b094176579c', '期待的广州花园酒店没有让我们失望
一进大堂就感受到大气，真金剪纸壁画显示了红楼梦的故事情节，流程和导引非常高效，办理入住的小丘非常专业和亲切，作为金卡会员不但给了升级还体贴地赠送了小朋友的早餐！非常感动！房间也非常舒适，门口就有地铁站 下次来一定还住这里', '["https://dimg04.c-ctrip.com/images/0231512000iar8c4n5AFD_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233u12000iar7h2x0352_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232q12000iar6fufDA16_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234z12000iar7slx56C0_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232312000iar7h39FE71_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234n12000iar8evb65C7_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232g12000iar7cmxBF0D_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 127, 0, 12, 9, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027941e3c98b094176579d', '这个酒店最难受的是开放式卫生间。洗澡间和卫生间共用一个推拉门；然后与床之间也是一个半玻璃门隔开的。俩人入住，一个人洗澡，另一个人最上卫生间就是敞开式，真是不方便。
     我们的房间外面有个大工地，似乎是在修地铁，工地的噪声夜里还是听的听清楚的。
   不过酒店的工作人员服务很不错！ 不管是大堂还是前台，房间、餐厅，服务人员都非常有礼貌。 早餐也算是丰富了。作为老牌五星级酒店，健身房确实差一些，尤其是健身人员素质太差（这个不能怪酒店）。
    酒店位置还不错，门口就有5号线地铁。', '["https://dimg04.c-ctrip.com/images/0231x12000hd5y20qD08C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000hd6wegvB624_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-12-23', '花园双床房', '双床房', '朋友出游', 244, 1, 25, 8, '["房间设施","安静程度","前台服务"]'::jsonb, '房间设施', '安静程度', '前台服务'),
('68027941e3c98b094176579e', '一如既往的好。作为广州地标酒店，也并不是停步不前，而是一直在进步。服务也有提升，谢谢小宁和小鱼。床品舒适。早餐比以前好吃了', '["https://dimg04.c-ctrip.com/images/0231912000jg74qanD577_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-31', '花园大床房', '大床房', '商务出差', 61, 0, 9, 7, '["整体满意度","房间设施","餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施'),
('68027941e3c98b094176579f', '过年安排在花园酒店，整个气氛很欢乐。酒店各个部门服务都很热情，在酒店用了早茶，也吃了年夜饭。新年第一天也看了舞狮。房间设施也很好。交通地铁也方便。', '["https://dimg04.c-ctrip.com/images/0233412000i8ryjk086EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000i8t39te9E7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-02', '花园大床房', '大床房', '家庭亲子', 73, 0, 32, 7, '["整体满意度","房间设施","交通便利性"]'::jsonb, '整体满意度', '房间设施', '交通便利性'),
('68027941e3c98b09417657a0', '其实是一家很有特色的酒店，只是酒廊太太太太太拉夸，餐食一般服务更差，严重减分。
先说有点：在寸土寸金的广州中心地带能拥有小桥流水的岭南风格园林，甚至还有专门为此准备的导览参观活动，足见花园酒店作为一家白金五星级酒店的实力。而且这家酒店负责房务的叔叔阿姨特别热情亲切，是我在别的酒店没有感受过的。
但是，三天两晚的住宿中，花园酒廊拙劣的服务让我和家人一次次感到震惊：先是第一晚，19时许进入酒廊后是一条非常昏暗的通道，唯一的光源就是桌子上的蓝色小夜灯，等走到中心区域后也没有空余座位，虽然当时有两名服务人员，但是并没有解决座位问题，只是表示只能坐在黑暗的过道区域座位，我们询问是否能将过道区域顶灯打开，服务人员竟然答复“老板不喜欢开灯，所以开不了”，最后我们通知当天外籍值班经理到场交涉，在表达了我们不满以及不开灯可能造成客人受伤等安全问题后，经过十多分钟协调才打开了灯。第二天下午，到酒廊享用下午茶，我母亲想坐在室外区域，询问当日酒廊外籍管理人员后表示户外区域是酒吧（对，酒吧酒廊共用一个区域）客人专属座位，我们便在室内区域落座，但是发现有多波酒廊客人落座户外区域，当时酒廊内客人不多且有三名以上工作人员，均没有对这种行为进行劝阻制止，甚至在酒廊客人是否可以坐在户外的问题上不同服务人员回答都有分歧，而我和母亲只是因为“听*话”就遭到了区别对待，让我们非常恼火。
以上情况，在向酒店值班经理等领导层反馈后，也只是得到了敷衍回答，并没有实际解决问题。
综上，花园酒店给我的感觉就是金絮其外败絮其中，顶着白金五星级酒店的名号，却在本应该是加分项的酒廊，给客人极差的体验。
顺便说一句，酒店酒吧酒廊共用空间，而酒吧并未按照《中华人民共和国未成年人保护法》第五十八条　（营业性酒吧等不适宜未成年人活动场所的经营者，不得允许未成年人进入。经营者应当在显著位置设置未成年人禁入、限入标志；对难以判明是否是未成年人的，应当要求其出示身份证件）规定执行，此情况已向相关部门反映，也请酒店积极整改！', '["https://dimg04.c-ctrip.com/images/0231s12000hzwsavu5CBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000hzwjuhzADB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000hzvxnj9B655_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000hzwzqh8C2C3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2025-01-22', '花园双床房', '双床房', '家庭亲子', 840, 0, 5, 9, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027941e3c98b09417657a1', '酒店超赞，不愧是白金五星，除了前台服务，其它酒店员工都很好。前台基本都板着脸，岭南金卡权益点一点拜一拜，不会主动把权益给你，赠送行政酒廊和早餐等，你提了，会给你加到备注里，不提就没有。', '["https://dimg04.c-ctrip.com/images/0236m12000hjj3qtf29AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000hji5rq590F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000hjijdy86431_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-01-02', '花园双床房', '双床房', '家庭亲子', 92, 0, 18, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027941e3c98b09417657a2', '升级了套房，对着花园瀑布，入住当天等了太久所以送了酒店的欢乐时光，早餐1楼是瀑布餐厅无猪肉非常适合挑食的我，30楼是旋转餐厅，都很有特色，酒店本身自带的花园很舒服。酒店服务很好，感谢热情的carrie小姐姐给我们拍照。空调和马桶年代久远来的时候维修耽误了时间，总体瑕不掩瑜。提一点建议，打电话问酒店要蚊香和晾衣架接线的人说没有，还好奇为啥五星酒店这都不配，但是最后都送过来了，接线员连感觉酒店有啥都不知道', '["https://dimg04.c-ctrip.com/images/0235i12000ighceckEC50_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000igh4mzp958E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000iggytz2825D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000ighbvieA6B2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-11', '花园双床房', '双床房', '家庭亲子', 202, 0, 18, 8, '["景观/朝向","餐饮设施","客房服务"]'::jsonb, '景观/朝向', '餐饮设施', '客房服务'),
('68027941e3c98b09417657a3', '大堂、餐厅、花园等公共区域环境很好。房间有点儿小，有咖啡机很不错，茶难喝，打扫的非常及时。
服务员及其多，都阳光靓丽，保持微笑服务。
购买的套餐是带行政礼遇、应该安排18-21层的房间。提醒过前台服务员后才看到，可能太忙了吧。
餐食挺好，早餐丰富，行政礼遇的下午茶阳光明媚、欢乐时光餐食比较丰富。', '["https://dimg04.c-ctrip.com/images/0233312000hb3jtl1CD0D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000hb3czzg8FDF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000hb4pyviEA53_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-12-20', '花园大床房', '大床房', '情侣出游', 148, 1, 17, 8, '["餐饮设施","前台服务","房间设施"]'::jsonb, '餐饮设施', '前台服务', '房间设施'),
('68027941e3c98b09417657a4', '老牌五星级酒店，设施不算新，但是干净整洁，服务态度好，酒店大堂金碧辉煌，香气弥漫，高级感十足，花园瀑布景观无敌，博物馆非常值得一逛，有金庸先生的墨宝。', '["https://dimg04.c-ctrip.com/images/0231012000i8e0n00E741_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000i8cbfhh3911_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000i8e1o3lEFA8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000i8dsb9k833D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000i8dzoum27DA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-02-01', '花园双床房', '双床房', '家庭亲子', 75, 0, 4, 8, '["景观/朝向","整体满意度","卫生状况"]'::jsonb, '景观/朝向', '整体满意度', '卫生状况'),
('68027941e3c98b09417657a5', '广州老牌五星酒店，新年期间很多庆祝活动，中外游客众多，服务很好，特别是一众酒店前台人员，亲切耐心，素质高，很能体现广州人热情好客的人文情怀。', '["https://dimg04.c-ctrip.com/images/0232q12000i4zxz7zE61B_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233412000i4zxdc23830_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233l12000i4zxah38109_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233c12000i4zxpyz28B0_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236012000i4zxpz649AB_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231o12000i4zy732CDC4_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231e12000i4zy8f01206_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233b12000i4zy094E756_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233m12000i4zy2dlC88D_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-01-29', '城央绿意双床房', '双床房', '家庭亲子', 70, 0, 2, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('6802794be3c98b09417657a6', '寸土尺金的地方，这个房间面积中规中矩
标配浴缸占用了空间，但确实也为这次住宿增添色彩，卫生间和淋浴间是分离，但空间很小，有点压抑感。酒廊是最好的体验，如果有机会下次再来尝试其他房型', '["https://dimg04.c-ctrip.com/images/0233w12000hiesw2t4939_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233h12000hiextnn873B_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230t12000hiex0yl581B_R_150_150_R5_Q70_D.png"]'::jsonb, 4.5, 4, '2024-12-31', '花园大床房', '大床房', '家庭亲子', 90, 0, 1, 7, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('6802794be3c98b09417657a7', '地理位置优越，很近地铁站，附近也有商铺配套设施。住了三晚，不错。送了水果盘，更意外的是刚好我生日，送了生日蛋糕，真的很惊喜。', '["https://dimg04.c-ctrip.com/images/0235212000ihpbcvf9FE8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000ihp7p031CBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000ihou6ku5975_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-13', '花园大床房', '大床房', '家庭亲子', 62, 0, 3, 7, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('6802794be3c98b09417657a8', '酒店地理位置优越，前台Gillian小姐姐服务很好，唯一不足的就是，房间布局有点不合理，卫生间，淋浴房共用一扇门，淋浴房和浴缸是一体的，老人和小朋友洗澡爬进爬出不太方便', '["https://dimg04.c-ctrip.com/images/0234k12000ho3sj93885D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000ho3s6iw2EED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000ho3wmmm66DF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-09', '花园大床房', '大床房', '家庭亲子', 84, 0, 29, 8, '["房间设施","前台服务","交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性'),
('6802794be3c98b09417657a9', '老牌的五星酒店，外国客人很多，服务员很热情，这点南方酒店胜出一大截。酒店出门就是地铁，工作日入住酒店给升了套间，本身的套餐包含了早餐和夜茶，所以性价比实在太高了。推荐！', '["https://dimg04.c-ctrip.com/images/0236s12000i9wmjzp3021_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000i9we0573795_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000i9wuyq39E38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000i9wnvw2438C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000i9wtu3jBDCC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000i9xd5t70FFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-03', '花园双床房', '双床房', '家庭亲子', 84, 0, 6, 8, '["性价比","交通便利性","前台服务"]'::jsonb, '性价比', '交通便利性', '前台服务'),
('6802794be3c98b09417657aa', '度假结束了，有时间来好好写点评，看中花园酒店的位置，定了套餐，更看重花园酒店的历史酒店礼宾部John下午的酒店导览对我们这次入住花园酒店是最大的加分，不仅让我们了解了花园酒店的历史更了解了广州作为我国改革开放前沿的窗口的不同，当内地还在继续计划经济的时候，广州已经在吸引外资了，我们的港澳同胞们作为祖国改革开放的坚定拥护者，爱国拳拳之心！花园酒店的花园，瀑布，大锦鲤都让人印象深刻，遗憾的是广州的美食太多，酒店的套餐都没来得及吃，唯一吃了一次早餐一楼是要排队的还是顶楼的比较好！再次感谢John给我们的导览，还有前台Betty的鲜花，给我们的圣诞假期带来了美好的开始！', '["https://dimg04.c-ctrip.com/images/0234512000hkooj6aE601_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000hkonnha36C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000hko1mh607DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000hko1mh8A492_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000hkntxug7CA5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-03', '花园双床房', '双床房', '家庭亲子', 284, 0, 0, 9, '["前台服务","周边配套","整体满意度"]'::jsonb, '前台服务', '周边配套', '整体满意度'),
('6802794be3c98b09417657ab', '装修很豪华美丽，外观、花园、大厅都非常漂亮，古典优雅，地段也很好，出行方便，周围吃喝玩乐都很丰富，但是毕竟是老酒店，房间很小，水池、浴室、墙角等角落也能看到发霉发黑，房间阴冷，被子也冰冰的，而且前台办入住非常慢，如果不是商务出行，自家出游的话，这个价位可以定综合水平更舒适的', '["https://dimg04.c-ctrip.com/images/0234112000hixaxjx28BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000hix76rs8B75_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2025-01-01', '花园双床房', '双床房', '商务出差', 137, 1, 4, 9, '["房间设施","前台服务","交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性'),
('6802794be3c98b09417657ac', '大堂美丽气派。红棉套房，新装修的，漂亮温馨。居住舒适。前台YOLO小姑娘热情解答各种问题。
涉外酒店??老外很多。感觉对内宾没有对外宾热情??
早餐自助瀑布餐厅人太多了，还没用完餐，桌子就被占领了??周围在施工有点不便。
西餐厅ZONA LIANG 非常热情，一直帮着拍照????', '["https://dimg04.c-ctrip.com/images/0232x12000h95p7rd41C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000h95mgxf7AC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000h95am0c8B18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-12-17', '红棉双床套房', '套房', '独自旅行', 140, 4, 26, 8, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('6802794be3c98b09417657ad', '房间很大，安静干净，早餐在一楼瀑布餐厅和30楼旋转餐厅，风景不错。前台服务员业务熟悉，态度热情，保安非常主动帮助拿行李。酒店很大，管理到位。', '["https://dimg04.c-ctrip.com/images/0230x12000i6jz8vj5F54_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000i6kc5nj5BEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000i6l0rwe785C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000i6lhpkwD0F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000i6kzz5196DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000i6lcdwx05E7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-31', '花园大床房', '大床房', '家庭亲子', 70, 0, 48, 8, '["整体满意度","前台服务","安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度'),
('6802794be3c98b09417657ae', '前两天住红棉很棒，照片是绿央的窗户，我理解不了同一个酒店怎么能脏成这样，房间不同内部设施有差别我能理解，大过年的窗户怎么能这么脏呢？', '["https://dimg04.c-ctrip.com/images/0236p12000i7jbiiuF052_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.1, 4, '2025-02-01', '城央绿意双床房', '双床房', '家庭亲子', 66, 0, 10, 7, '["卫生状况","房间设施"]'::jsonb, '卫生状况', '房间设施', NULL),
('6802794be3c98b09417657af', '舒适、出入方便，中餐和西餐都是米其林餐厅，出品非常好，服务态度超好，大堂的咖啡厅做的点心也非常棒！所以每次来广州都是首选。', '["https://dimg04.c-ctrip.com/images/0235j12000jvf0cv0C9EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000jvdcnk96F6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000jve7r5sBB0B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000jvejcakC3C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000jvf9jra3BB8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-17', '花园大床房', '大床房', '商务出差', 61, 0, 26, 7, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68027957e3c98b09417657b0', '房间整洁卫生，环境优美。liven服务很好。适合亲子旅行。', '["https://dimg04.c-ctrip.com/images/0231712000jlp19tnBAF6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-06', '花园双床房', '双床房', '家庭亲子', 29, 0, 4, 5, '["卫生状况","整体满意度","前台服务"]'::jsonb, '卫生状况', '整体满意度', '前台服务'),
('68027957e3c98b09417657b1', '超预期的好，豪华酒店的调性和标准在线，老酒店有新装修后也非常棒，赞，服务很好，谢谢Mancy的安排。这位置很好，去哪都方便，下次再见', '["https://dimg04.c-ctrip.com/images/0232l12000iayx267FEBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000iazkf7t8F69_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000iayxobtDDF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-04', '花园大床房', '大床房', '家庭亲子', 66, 0, 9, 7, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027957e3c98b09417657b2', '房间很大很干净卫生，在房间可以自己煮咖啡，有两个洗手盆，很方便。服务态度很好，在上下电梯口都有服务员服务，出入酒店门口也有服务员开门，很礼貌，贵宾待遇！餐饮也不错', '["https://dimg04.c-ctrip.com/images/0231912000hyuswmjEA48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000hyv6zkr081C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000hyvs2j991DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000hyubkcmEA14_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000hyukb573BA5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-21', '花园双床房', '双床房', '家庭亲子', 81, 0, 44, 8, '["房间设施","前台服务","卫生状况"]'::jsonb, '房间设施', '前台服务', '卫生状况'),
('68027957e3c98b09417657b3', '到酒店那天，出租车到正门口，没有服务员来开门与拿行李，我们带着孩子自己拿大包小包进门的。
酒店虽然不是很新，但是维护的很好。我们带小孩，酒店没有床围，我们订的房型大床才1.8米，没办法睡觉，交涉后才给我们升级了房型，但是真正入住是到5、6点才好的。我们吃完饭才回大堂拿了房卡并知道了房号，真的是第一次的体验。
再有希望卫生间可以有马桶冲洗功能，实在是不习惯。另外周边在修马路，房间里还是可以听到修路的噪音。其余都还行，反正挺适合商务的，不适合亲子出行。', '["https://dimg04.c-ctrip.com/images/0231t12000h4hbrq9A001_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000h4hdkx5C89B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000h4hlnmbE4DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000h4he3ja3D35_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-12-09', '花园双床房', '双床房', '家庭亲子', 226, 1, 5, 8, '["房间设施","前台服务","安静程度"]'::jsonb, '房间设施', '前台服务', '安静程度'),
('68027957e3c98b09417657b4', '位置优越，地铁口出来就是酒店非常方便，赶着过年去的人很多房间还没收拾好，直接送了两份早餐，酒廊的下午茶也可以随时都能去，好评??', '["https://dimg04.c-ctrip.com/images/0235112000icjqne085FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000icj6jd3A415_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000ick7wqa1BA8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-06', '粤韵大床套房', '套房', '家庭亲子', 64, 0, 7, 7, '["交通便利性","餐饮设施","退房/入住效率"]'::jsonb, '交通便利性', '餐饮设施', '退房/入住效率'),
('68027957e3c98b09417657b5', '非常满意的一次入住，很喜欢酒店的历史年代感，有机会还会考虑入住。酒店早餐也很丰富，瀑布花园也特别可爱。', '["https://dimg04.c-ctrip.com/images/0231a12000jvql5yx0043_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000jvpzpvzE15E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000jvqpi4n8C1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000jvqd5w97B00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000jvpyug672D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000jvouo0aFCEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000jvpl5flB3FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000jvpl5fn0698_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000jvqcjve5FCF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-17', '花园双床房', '双床房', '家庭亲子', 51, 0, 8, 6, '["整体满意度","餐饮设施"]'::jsonb, '整体满意度', '餐饮设施', NULL),
('68027957e3c98b09417657b6', '选中这个酒店是看中它的环境非常漂亮。实际入住后，不仅环境漂亮，工作人员服务也很热情。他们会热情的和你打招呼，需要帮助时也会立即上前。', '["https://dimg04.c-ctrip.com/images/0232u12000i6obf5k2195_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000i6p2wkvFFD9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000i6nw2ujDA7A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-31', '花园双床房', '双床房', '家庭亲子', 66, 0, 7, 7, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027957e3c98b09417657b7', '20年前第一次出差就住花园酒店，每次来广州都住这里，酒店员工很友好、服务很好??', '["https://dimg04.c-ctrip.com/images/0236h12000j2klcf3E2BB_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231612000j2klcf9222F_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232c12000j2ko2nvF20F_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-03-14', '花园大床房', '大床房', '商务出差', 40, 0, 2, 5, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027957e3c98b09417657b8', '房间和外部看的出年份，也看的出一直不断改进的影子，总体对得起5星，携程的套餐写的定制早餐也没明确指引，早餐地方太多了。', '["https://dimg04.c-ctrip.com/images/0230612000ib2kfx7AF31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000ib24mvs009C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000ib20133B71A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 59, 0, 25, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027957e3c98b09417657b9', '卫生：房间卫生干净整洁

环境：酒店氛围很好，很有感觉

服务：Tina小姐姐人美服务好

推荐推荐～下次来还选择', '["https://dimg04.c-ctrip.com/images/0230t12000jrli0jd418A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000jrlmjl72971_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000jrljsrb2AC8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000jrlj2d19CC2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-13', '城央绿意大床房', '大床房', '情侣出游', 57, 0, 6, 5, '["卫生状况","整体满意度","前台服务"]'::jsonb, '卫生状况', '整体满意度', '前台服务'),
('68027962e3c98b09417657ba', '还不错，为了情怀住的，就是楼下施工有时候会有点吵吧。', '["https://dimg04.c-ctrip.com/images/0231812000jq7e560B1F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000jq8qflr24F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000jq8n28n6E35_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-11', '红棉双床套房', '套房', '家庭亲子', 26, 0, 2, 4, '["安静程度","整体满意度"]'::jsonb, '安静程度', '整体满意度', NULL),
('68027962e3c98b09417657bb', '一个将近40年的酒店，服务不负超白金的口碑，花园很美，但是酒店的洗手间太小，门的设计不是很合理，隐秘性不够，最好能改进。', '["https://dimg04.c-ctrip.com/images/0233y12000i81rpqp362D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000i818xadDF31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000i819ccs185A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-01', '城央绿意双床房', '双床房', '家庭亲子', 60, 0, 12, 7, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027962e3c98b09417657bc', '酒店不错非常漂亮??值班经理六小龄童非常热情专业，推荐推荐，下次一定再来', '["https://dimg04.c-ctrip.com/images/0234h12000j8bv325F747_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-21', '花园大床房', '大床房', '商务出差', 36, 0, 1, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027962e3c98b09417657bd', '景色超级美 后花园很值得一逛。酒店有点旧了但是保养的不错 卫生做的很干净 所有工作人员服务态度也很好 推荐入住感受一下', '["https://dimg04.c-ctrip.com/images/0236a12000i7vm6e1D00D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000i7vrfk66B26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000i7trginE67D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-01', '花园大床房', '大床房', '家庭亲子', 59, 0, 4, 7, '["整体满意度","卫生状况","景观/朝向"]'::jsonb, '整体满意度', '卫生状况', '景观/朝向'),
('68027962e3c98b09417657be', '来广州住这个酒店很开心的。酒店大堂宽敞明亮，各种设施齐全，酒店的花园景观别致，服务人员随时给提供帮助，早餐很美味', '["https://dimg04.c-ctrip.com/images/0235h12000iidf3vz7A5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000iiccf3i9789_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000iicerb997BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-13', '花园双床房', '双床房', '家庭亲子', 56, 0, 11, 7, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68027962e3c98b09417657bf', '整体体验还是挺不错的，老牌酒店很有韵味，酒店里的内容也很丰富，博物馆很用心的了。房间层走廊确实比较偏低，但也是那个年代的特殊产物。房间里头淋浴间和厕所的门只能关其一的设计比较神奇，但其实也不太方便，尤其是双床房的话。水龙头的位置让水开大的时候容易溅出来。', '["https://dimg04.c-ctrip.com/images/0231v12000gz7miui60BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000gz78s4u7A76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000gz78h4q3C1A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2024-12-01', '花园双床房', '双床房', '情侣出游', 127, 2, 19, 7, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027962e3c98b09417657c0', '过年期间去的，酒店非常有节日氛围，家人都非常满意。酒店服务也非常好，还送了下午茶，房间升了级！选对了一切都是最好的安排！', '["https://dimg04.c-ctrip.com/images/0234i12000iiojx2vA6DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000iipx18t24F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-14', '红棉大床套房', '套房', '家庭亲子', 60, 0, 13, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027962e3c98b09417657c1', '结论：整家酒店充斥着老广的精明算计和散漫。

先说优点：设计经典、大堂富丽堂皇、博物馆用心、后花园不错、房间维护尚可（红棉）、服务人员主动问好。

再说槽点，实在太多了，只能挑重点讲。

1. 前台极其不专业：效率低，排队久，期间还被几个老头插队。最活久见的是，办完给房卡，哪里坐电梯、几点吃早餐在哪里、酒店有什么设施全靠自己问，这东西不应该是主动介绍的吗？

2. 流程是混乱的。举个例子：早餐到了瀑布餐厅，说要排队，让去旋转餐厅，说那里人少，不用排队，到了 30 楼之后，跟我说前面还要等三桌。我？？？最关键是看到餐厅里还有好几张空桌子，写着 reserved，那好，你们早餐还需要预定我接受，那么能不能入住的时候提前告知我预定方式？？ 还有晚餐，打电话订荔湾亭，说订满了，问说想吃怎么办，必须 7 点半以后再来排队，来早了都不行；对比白天鹅宾馆，人家玉堂春暖提前一周打电话主动提醒预定，并且住店客人有优先预定权。随后订桃园馆，桃园馆问我是哪个房间的？因为酒店跟餐厅是分开运营的，所以还得留一遍电话。最关键的来了，结账说挂账，服务员说押金不够，我说不够那我现场补？不行，生带着我走回一楼前台刷了押金。

3. 服务人员素质参差不齐，看人下菜。为什么说参差不齐，是因为我觉得有些工作人员很认真负责，比如博物馆；因为订的携程套餐包含了小礼物，前台不会主动说，问了就说去给你找，然后还要提前强调这是随机的哦不能选，绝了；对比之前住过的君悦，人家公仔或者小朋友玩具都是主动赠予的，花园酒店是你去要，要完还跟你说不能随便选。桃园中餐厅，连续 7 年的米其林，点菜的时候跟我说房间五折这不能用那不能用，我寻思算了就点按道上的套餐好了，菜单拿过来，直接甩一句“我们套餐最便宜一个人 388”，醉了。米其林吃过不止 10 家，第一次被这么服务。

4. 还有一些其他的住多了五星级就容易发现的毛病，比如: 酒店大堂混乱（来回几次没见着大堂经理）各种网红 司机 游客，比较无序；房间洗手台设计容易溢水以及马桶浴缸非常旧（无智能马桶就不说了 每盖一次 bang 的巨响一次）；四楼酒店还连着一堆对外出租的写字楼并且看到有非酒店住客过来健身的（对外出租创收没问题但请确保隐私性）；楼下淘金站有大型工地，噪音不小，没办法睡午觉，这个很多人都提过，不再赘述。

总而言之：当初抱着对全国唯一一家民族品牌白金五星级的期待来，来了之后有点担心这样的酒店管理对不起贝聿铭先生的设计，对不起邓小平的题字，对不起“民族品牌”四个字。', '["https://dimg04.c-ctrip.com/images/0235212000gza72rg4033_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000gz9mg8x5D95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000gz9mzqgCBF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000gzabr4aB3B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000gz9fnid7CDC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000gz9o1a1E6E7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000gz9eg9gCB7C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.6, 2, '2024-12-01', '红棉大床套房', '套房', '家庭亲子', 1050, 37, 2, 9, '["前台服务","整体满意度","退房/入住效率"]'::jsonb, '前台服务', '整体满意度', '退房/入住效率'),
('68027962e3c98b09417657c2', '都不能手机充电，个个插头都很松，一半不能用', '["https://dimg04.c-ctrip.com/images/0233c324x90k6ftd3BBBD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2025-04-13', '花园双床房', '双床房', '独自旅行', 21, 0, 41, 6, '["房间设施"]'::jsonb, '房间设施', NULL, NULL),
('68027962e3c98b09417657c3', '除了房间小点，设施旧点，其他都很好，有庞大的花园，有很多餐厅，有酒店博物馆，服务员也很年轻，如果没去过可以去一次', '["https://dimg04.c-ctrip.com/images/0235n12000ioq8nkh6FDC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000iopduxb0DC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000ior2hu47923_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-23', '花园双床房', '双床房', '家庭亲子', 56, 0, 4, 7, '["房间设施","公共设施","整体满意度"]'::jsonb, '房间设施', '公共设施', '整体满意度'),
('68027971e3c98b09417657c4', '服务相当满意，特别点赞酒廊的Carrie。每天早上每层电梯口都有小姐姐帮助乘电梯和指引歺厅，1.2. 图片，瀑布餐厅，3.4图行政酒廊 ，5.6图30层的旋转餐厅，每个餐厅的景各有特色都很不错，喜欢30层的旋转餐厅，可以边吃早餐边欣赏酒店周围360度的城市景观，每个餐厅的服务都是相当的令人满意??', '["https://dimg04.c-ctrip.com/images/0230612000h062uei61A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000h0644g9723C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000h062x2y42D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000h05vzij9DF8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000h05u4ywEB03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000h05u2jp7618_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000h05sh605C11_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-03', '花园大床房', '大床房', '情侣出游', 149, 1, 4, 8, '["餐饮设施","前台服务","景观/朝向"]'::jsonb, '餐饮设施', '前台服务', '景观/朝向'),
('68027971e3c98b09417657c5', '全国三家白金五星级酒店之一，各项设施服务都是首屈一指的。
带妈妈去广州玩，选择在这里入住，交通方便，景观一流，服务周到，前台还免费升级了套房，是很好的体验。', '["https://dimg04.c-ctrip.com/images/0235c12000id0zp27683D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000id1w257ACD6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000id1hhxvF197_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000id1ht02D63D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000id1hk6jD18E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000id1fyvwB739_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000id17d1859CA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-07', '花园双床房', '双床房', '家庭亲子', 78, 0, 27, 8, '["整体满意度","交通便利性","景观/朝向"]'::jsonb, '整体满意度', '交通便利性', '景观/朝向'),
('68027971e3c98b09417657c6', '房间虽然不大但配置很齐全，服务很好，非常满意的一次体验！套餐包含的东西也很正！酒店环境和位置是真的好到没得说！', '["https://dimg04.c-ctrip.com/images/0234s12000idfrefv8101_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234k12000idfm1gc36B2_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-02-07', '花园双床房', '双床房', '家庭亲子', 55, 0, 14, 7, '["整体满意度","房间设施","周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套'),
('68027971e3c98b09417657c7', '前台02工作人员服务专业效率高几分钟就办好了入住手续，还主动帮我们升级了房间太惊喜了，无论是咨询还是解决问题都非常迅速，让人感到非常安心。', '["https://dimg04.c-ctrip.com/images/0230512000imnpg6p443A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000imo3xpd6FE6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000imnmd0zCEC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000imn90yw0583_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-20', '红棉大床套房', '套房', '商务出差', 69, 0, 5, 9, '["前台服务","退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL),
('68027971e3c98b09417657c8', '酒店位置非常好，离地铁近，酒店门口一直有排队的出租车，出行方便，酒店大堂很漂亮，房间忘了拍照了，酒店早餐丰富', '["https://dimg04.c-ctrip.com/images/0232u12000ibpdzcb794A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-05', '城央绿意双床房', '双床房', '家庭亲子', 54, 0, 22, 7, '["交通便利性","周边配套","餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施'),
('68027971e3c98b09417657c9', '房间窗户一点点都不能打开通风，房间设施维护比较一般。房间很小，两个人住，卫生间都转不了身。住了两个晚上，行政酒廊都挺好吃，即使快结束了，看到有人来，还会补吃的。在此特别感谢印度裔Carrie，服务特别亲切，表扬Carrie，唯独你留下了好印象。其他的服务人员都不咋滴了，特别是前台办理入住的人员得多加培训，感觉对工作有怨气。', '["https://dimg04.c-ctrip.com/images/0236712000i5rqw1g67DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000i5qw0b62CBE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-01-30', '花园大床房', '大床房', '家庭亲子', 162, 0, 37, 8, '["房间设施","前台服务","餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施'),
('68027971e3c98b09417657ca', '酒店在市区，周边就是商场，酒店门口车子多，看来入住的人也比较多，店内服务先生小姐热情，办入住的时候还收到送的鲜花好开心，同时也看到沙特航空公司的几位漂亮小姐?也在办理入住，酒店有不少外宾入住，酒店楼上有一个层面还有介绍该酒店的一个历史的博物馆，?我也进去参观了挺好的，酒店有40多年历史不少名人居住过大名在外，店内大堂气派，早餐丰富，味道也好，用早餐的地方也能看到窗外的人造瀑布?。因为酒店建得早停车要停到地下人上来的时候要绕一条过道从酒店后门进酒店?不是太方便，房间干净，样式老了一点，在房间也收到了酒店送的送了点心好温馨，谢谢酒店了！??', '["https://dimg04.c-ctrip.com/images/0202012000gwimnzf97E3_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0203x12000gwinczqBE56_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0233k12000gwiguwn5F3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000gwi37hk041F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-27', '花园双床房', '双床房', '其他', 271, 0, 37, 9, '["周边配套","整体满意度","前台服务"]'::jsonb, '周边配套', '整体满意度', '前台服务'),
('68027971e3c98b09417657cb', '设施：老牌五星，铂金。就缺晾衣服的
卫生：很好，
环境：花园和瀑布还有鱼，娃很喜欢
服务：细心，看喝水情况给矿泉水。', '["https://dimg04.c-ctrip.com/images/0231612000ido1h2i89A1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-07', '红棉大床套房', '套房', '家庭亲子', 58, 0, 6, 7, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027971e3c98b09417657cc', '不愧是老牌五星级酒店，虽然设施老了一点，但服务人员热情，春节期间酒店氛围热闹，家人住得特别开心，有机会会再次入住', '["https://dimg04.c-ctrip.com/images/0235c12000ibhujet741C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000ibi6ety288C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-05', '花园双床房', '双床房', '家庭亲子', 56, 0, 4, 7, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027971e3c98b09417657cd', '房间很舒服，酒店各方面服务好，尤其是餐饮的服务态度亲切，业务专业，早餐可以四个餐厅用，满足了不同体验，期盼下次继续入住', '["https://dimg04.c-ctrip.com/images/0231b12000ifp17d5326F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000ifppqm1A7EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000ifpznntB615_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000ifqxuxi8998_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-10', '红棉双床套房', '套房', '家庭亲子', 59, 0, 24, 7, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务')
